<h1 class="h3 mb-3">Movimientos pendientes de revisión</h1>
<div class="card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Fecha</th><th>Concepto</th><th class="text-end">Importe</th><th>Clasificar</th></tr></thead><tbody><?php foreach ($movements as $m): ?><tr><td><?= e($m['fecha']) ?></td><td><?= e($m['concepto_banco']) ?><div class="small text-muted"><?= e($m['mas_datos']) ?></div></td><td class="text-end <?= $m['tipo']==='ingreso'?'amount-income':'amount-expense' ?>"><?= money($m['importe']) ?></td><td><form method="post" action="?route=pending_update" class="row g-2"><input type="hidden" name="id" value="<?= $m['id'] ?>"><input type="hidden" name="tipo" value="<?= e($m['tipo']) ?>"><div class="col-md-3"><select name="categoria_id" class="form-select form-select-sm" required><?php foreach ($categories as $c): ?><option value="<?= $c['id'] ?>"><?= e($c['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><select name="subcategoria_id" class="form-select form-select-sm" required><?php foreach ($subcategories as $s): ?><option value="<?= $s['id'] ?>"><?= e($s['categoria'] . ' / ' . $s['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><input name="palabra_clave" class="form-control form-control-sm" value="<?= e(strtok($m['concepto_banco'], ' ')) ?>" placeholder="Palabra clave"></div><div class="col-md-2"><label class="form-check small"><input class="form-check-input" type="checkbox" name="crear_regla" value="1" checked> Crear regla</label></div><div class="col-md-1"><button class="btn btn-sm btn-primary">OK</button></div></form></td></tr><?php endforeach; ?></tbody></table></div></div>
